6. {
7.     public class PaginatedList<T> : List<T>
8.     {
9.         public int PageIndex { get; private set; }
10.         public int TotalPages { get; private set; }
11. 
12.         public PaginatedList(List<T> items, int count, int pageIndex, int pageSize)
13.         {
14.             PageIndex = pageIndex;
15.             TotalPages = (int)Math.Ceiling(count / (double)pageSize);
16. 
17.             this.AddRange(items);
18.         }
19. 
20.         public bool HasPreviousPage => PageIndex > 1;
21. 
22.         public bool HasNextPage => PageIndex < TotalPages;
23. 
24.         public static PaginatedList<T> Create(IQueryable<T> source, int pageIndex, int pageSize)
25.         {
26.             var count = source.Count();
27.             var items = source.Skip((pageIndex - 1) * pageSize).Take(pageSize).ToList();
28.             return new PaginatedList<T>(items, count, pageIndex, pageSize);
29.         }
30.     }
