using ContosoUniversity.Data;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers;

public static class TestDbContextFactory
{
    public static SchoolContext Create()
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
            .Options;

        var context = new SchoolContext(options);
        context.Database.EnsureCreated();
        return context;
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new NotificationService();
        // Drain any leftover notifications from static queue
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        // Drain queue after each test
        while (_sut.ReceiveNotification() != null) { }
        _sut.Dispose();
    }

    [TestMethod]
    public void SendNotification_FourParamOverload_EnqueuesNotification()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("System", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_FiveParamOverload_EnqueuesNotificationWithDisplayName()
    {
        // Act
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsTrue(notification.Message.Contains("John Doe"));
    }

    [TestMethod]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        _sut.SendNotification("Course", "101", EntityOperation.UPDATE);

        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        var result = _sut.ReceiveNotification();
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_PopulatedQueue_ReturnsAndRemovesNotification()
    {
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);
        _sut.SendNotification("Student", "2", EntityOperation.UPDATE);

        var first = _sut.ReceiveNotification();
        Assert.IsNotNull(first);
        Assert.AreEqual("1", first.EntityId);

        var second = _sut.ReceiveNotification();
        Assert.IsNotNull(second);
        Assert.AreEqual("2", second.EntityId);

        var third = _sut.ReceiveNotification();
        Assert.IsNull(third);
    }

    [TestMethod]
    public void GenerateMessage_Create_ReturnsCorrectMessage()
    {
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("New Student 'John Doe' has been created", notification!.Message);
    }

    [TestMethod]
    public void GenerateMessage_Update_ReturnsCorrectMessage()
    {
        _sut.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE);
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("Course 'Chemistry' has been updated", notification!.Message);
    }

    [TestMethod]
    public void GenerateMessage_Delete_ReturnsCorrectMessage()
    {
        _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("Department 'Engineering' has been deleted", notification!.Message);
    }

    [TestMethod]
    public void GenerateMessage_NoDisplayName_UsesIdFormat()
    {
        _sut.SendNotification("Student", "42", null, EntityOperation.CREATE);
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("New Student (ID: 42) has been created", notification!.Message);
    }

    [TestMethod]
    public void GenerateMessage_EmptyDisplayName_UsesIdFormat()
    {
        _sut.SendNotification("Student", "42", "", EntityOperation.UPDATE);
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("Student (ID: 42) has been updated", notification!.Message);
    }

    [TestMethod]
    public void GenerateMessage_WhitespaceDisplayName_UsesIdFormat()
    {
        _sut.SendNotification("Student", "42", "   ", EntityOperation.DELETE);
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("Student (ID: 42) has been deleted", notification!.Message);
    }

    [TestMethod]
    public void SendNotification_QueueCapEnforcement_OldestItemsRemoved()
    {
        // Enqueue more than 500 items
        for (int i = 0; i < 510; i++)
        {
            _sut.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
        }

        // Count remaining items
        int count = 0;
        while (_sut.ReceiveNotification() != null) count++;

        Assert.IsTrue(count <= 500, $"Queue should be capped at 500 but had {count} items");
    }

    [TestMethod]
    public void SendNotification_CreatedAtIsSet()
    {
        var before = DateTime.Now.AddSeconds(-1);
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);
        var after = DateTime.Now.AddSeconds(1);

        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
            $"CreatedAt {notification.CreatedAt} not in expected range [{before}, {after}]");
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        var service = new NotificationService();
        service.Dispose();
        // No exception means success
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op but should not throw
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(999);
    }
}

namespace ContosoUniversity.Tests.Helpers;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 5);

        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(5, result[4]);
        Assert.AreEqual(1, result.PageIndex);
    }

    [TestMethod]
    public void Create_SecondPage_ReturnsCorrectItems()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var result = PaginatedList<int>.Create(source, 2, 5);

        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(6, result[0]);
        Assert.AreEqual(10, result[4]);
        Assert.AreEqual(2, result.PageIndex);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        var source = Enumerable.Range(1, 12).AsQueryable();

        var result = PaginatedList<int>.Create(source, 3, 5);

        Assert.AreEqual(2, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(12, result[1]);
    }

    [TestMethod]
    public void TotalPages_ExactDivision_CalculatedCorrectly()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 5);

        Assert.AreEqual(4, result.TotalPages);
    }

    [TestMethod]
    public void TotalPages_PartialLastPage_RoundsUp()
    {
        var source = Enumerable.Range(1, 11).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 5);

        Assert.AreEqual(3, result.TotalPages);
    }

    [TestMethod]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 5);

        Assert.IsFalse(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var result = PaginatedList<int>.Create(source, 2, 5);

        Assert.IsTrue(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var result = PaginatedList<int>.Create(source, 4, 5);

        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_FirstPage_ReturnsTrue()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 5);

        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<int>().AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 5);

        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_PageBeyondRange_ReturnsEmptyList()
    {
        var source = Enumerable.Range(1, 5).AsQueryable();

        var result = PaginatedList<int>.Create(source, 5, 5);

        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(1, result.TotalPages);
    }

    [TestMethod]
    public void Create_SingleItem_SinglePage()
    {
        var source = new[] { 42 }.AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.AreEqual(1, result.Count);
        Assert.AreEqual(42, result[0]);
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_PageSize1_PaginatesCorrectly()
    {
        var source = Enumerable.Range(1, 3).AsQueryable();

        var page1 = PaginatedList<int>.Create(source, 1, 1);
        var page2 = PaginatedList<int>.Create(source, 2, 1);
        var page3 = PaginatedList<int>.Create(source, 3, 1);

        Assert.AreEqual(1, page1.Count);
        Assert.AreEqual(1, page1[0]);
        Assert.AreEqual(3, page1.TotalPages);

        Assert.AreEqual(1, page2.Count);
        Assert.AreEqual(2, page2[0]);

        Assert.AreEqual(1, page3.Count);
        Assert.AreEqual(3, page3[0]);
        Assert.IsFalse(page3.HasNextPage);
    }

    [TestMethod]
    public void Constructor_SetsProperties()
    {
        var items = new List<string> { "a", "b", "c" };

        var result = new PaginatedList<string>(items, 10, 2, 3);

        Assert.AreEqual(3, result.Count);
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages); // ceil(10/3) = 4
        Assert.IsTrue(result.HasPreviousPage);
        Assert.IsTrue(result.HasNextPage);
    }
}

