        var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
        svc.Dispose();
    }

    [TestCleanup]
    public void Cleanup()
    {
        var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
        svc.Dispose();
        _sut.Dispose();
        _context.Dispose();
    }

    private void SeedStudents()
    {
        _context.Students.AddRange(
            new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = new DateTime(2021, 9, 1) },
            new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = new DateTime(2019, 9, 1) }
        );
        _context.SaveChanges();
    }

    // === Index Tests ===

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithStudentsOrderedByLastName()
    {
        SeedStudents();

        var result = _sut.Index(null, null, null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
        Assert.AreEqual("Anand", model[2].LastName);
    }

    [TestMethod]
    public void Index_NameDesc_ReturnsStudentsOrderedByLastNameDescending()
    {
        SeedStudents();

        var result = _sut.Index("name_desc", null, null, null) as ViewResult;

        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Anand", model[0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
        Assert.AreEqual("Alexander", model[2].LastName);
    }

    [TestMethod]
    public void Index_DateSort_ReturnsStudentsOrderedByDateAscending()
    {
        SeedStudents();

        var result = _sut.Index("Date", null, null, null) as ViewResult;

        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Anand", model[0].LastName); // 2019
        Assert.AreEqual("Alexander", model[1].LastName); // 2020
        Assert.AreEqual("Alonso", model[2].LastName); // 2021
    }

    [TestMethod]
    public void Index_DateDescSort_ReturnsStudentsOrderedByDateDescending()
    {
        SeedStudents();

        var result = _sut.Index("date_desc", null, null, null) as ViewResult;

        var model = result!.Model as PaginatedList<Student>;
