namespace ContosoUniversity.Tests.Data;

[TestClass]
public sealed class DbInitializerTests
{
    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsAllEntities()
    {
        using var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        Assert.AreEqual(8, context.Students.Count());
        Assert.AreEqual(5, context.Instructors.Count());
        Assert.AreEqual(4, context.Departments.Count());
        Assert.AreEqual(7, context.Courses.Count());
        Assert.AreEqual(3, context.OfficeAssignments.Count());
        Assert.AreEqual(8, context.CourseAssignments.Count());
        Assert.IsTrue(context.Enrollments.Count() > 0);
    }

    [TestMethod]
    public void Initialize_DatabaseAlreadySeeded_DoesNotDuplicate()
    {
        using var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);
        DbInitializer.Initialize(context); // Run again

        Assert.AreEqual(8, context.Students.Count());
        Assert.AreEqual(5, context.Instructors.Count());
    }

    [TestMethod]
    public void Initialize_SeedsCorrectStudentNames()
    {
        using var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        var students = context.Students.OrderBy(s => s.LastName).ToList();
        Assert.AreEqual("Alexander", students[0].LastName);
        Assert.AreEqual("Carson", students[0].FirstMidName);
    }

    [TestMethod]
    public void Initialize_SeedsCorrectDepartmentBudgets()
    {
        using var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        var english = context.Departments.Single(d => d.Name == "English");
        Assert.AreEqual(350000m, english.Budget);

        var math = context.Departments.Single(d => d.Name == "Mathematics");
        Assert.AreEqual(100000m, math.Budget);
    }

    [TestMethod]
    public void Initialize_SeedsCoursesWithCorrectCredits()
    {
        using var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        var chemistry = context.Courses.Single(c => c.Title == "Chemistry");
        Assert.AreEqual(3, chemistry.Credits);
        Assert.AreEqual(1050, chemistry.CourseID);

        var calculus = context.Courses.Single(c => c.Title == "Calculus");
        Assert.AreEqual(4, calculus.Credits);
        Assert.AreEqual(1045, calculus.CourseID);
    }

    [TestMethod]
    public void Initialize_SeedsOfficeAssignments()
    {
        using var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        var offices = context.OfficeAssignments.ToList();
        Assert.AreEqual(3, offices.Count);
        Assert.IsTrue(offices.Any(o => o.Location == "Smith 17"));
        Assert.IsTrue(offices.Any(o => o.Location == "Gowan 27"));
        Assert.IsTrue(offices.Any(o => o.Location == "Thompson 304"));
    }

    [TestMethod]
    public void Initialize_SeedsEnrollmentsWithGrades()
    {
        using var context = TestDbContextFactory.Create();

        DbInitializer.Initialize(context);

        var enrollments = context.Enrollments.ToList();
        Assert.IsTrue(enrollments.Count >= 11);
        Assert.IsTrue(enrollments.Any(e => e.Grade == Grade.A));
        Assert.IsTrue(enrollments.Any(e => e.Grade == null)); // Anand's Chemistry enrollment has no grade
    }
}

using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Data;

[TestClass]
public sealed class SchoolContextTests
{
    [TestMethod]
    public void SchoolContext_HasAllDbSets()
    {
        using var context = TestDbContextFactory.Create();

        Assert.IsNotNull(context.Courses);
        Assert.IsNotNull(context.Enrollments);
        Assert.IsNotNull(context.Departments);
        Assert.IsNotNull(context.OfficeAssignments);
        Assert.IsNotNull(context.CourseAssignments);
        Assert.IsNotNull(context.People);
        Assert.IsNotNull(context.Students);
        Assert.IsNotNull(context.Instructors);
        Assert.IsNotNull(context.Notifications);
    }

    [TestMethod]
    public void CourseAssignment_HasCompositeKey()
    {
        using var context = TestDbContextFactory.Create();

        var entityType = context.Model.FindEntityType(typeof(CourseAssignment));
        Assert.IsNotNull(entityType);

        var primaryKey = entityType.FindPrimaryKey();
        Assert.IsNotNull(primaryKey);
        Assert.AreEqual(2, primaryKey.Properties.Count);

        var keyNames = primaryKey.Properties.Select(p => p.Name).ToList();
        Assert.IsTrue(keyNames.Contains("CourseID"));
        Assert.IsTrue(keyNames.Contains("InstructorID"));
    }

    [TestMethod]
    public void Person_UsesTPHInheritance()
    {
        using var context = TestDbContextFactory.Create();

        var personType = context.Model.FindEntityType(typeof(Person));
        Assert.IsNotNull(personType);

        var studentType = context.Model.FindEntityType(typeof(Student));
        Assert.IsNotNull(studentType);
        Assert.AreEqual(personType.GetTableName(), studentType.GetTableName());

        var instructorType = context.Model.FindEntityType(typeof(Instructor));
        Assert.IsNotNull(instructorType);
        Assert.AreEqual(personType.GetTableName(), instructorType.GetTableName());
    }

    [TestMethod]
    public void OfficeAssignment_HasInstructorIDAsKey()
    {
        using var context = TestDbContextFactory.Create();

        var entityType = context.Model.FindEntityType(typeof(OfficeAssignment));
        Assert.IsNotNull(entityType);

        var primaryKey = entityType.FindPrimaryKey();
        Assert.IsNotNull(primaryKey);
        Assert.AreEqual(1, primaryKey.Properties.Count);
        Assert.AreEqual("InstructorID", primaryKey.Properties[0].Name);
    }

    [TestMethod]
    public void Student_CanBeSavedAndRetrieved()
    {
        using var context = TestDbContextFactory.Create();

        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };
        context.Students.Add(student);
        context.SaveChanges();

        var retrieved = context.Students.First();
        Assert.AreEqual("Test", retrieved.FirstMidName);
        Assert.AreEqual("Student", retrieved.LastName);
        Assert.AreEqual(new DateTime(2023, 9, 1), retrieved.EnrollmentDate);
    }

    [TestMethod]
    public void Instructor_CanHaveOfficeAssignment()
    {
        using var context = TestDbContextFactory.Create();

        var instructor = new Instructor
        {
            FirstMidName = "Kim",
            LastName = "Test",
            HireDate = new DateTime(2000, 1, 1),
            OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
        };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        var retrieved = context.Instructors.Include(i => i.OfficeAssignment).First();
        Assert.IsNotNull(retrieved.OfficeAssignment);
        Assert.AreEqual("Room 101", retrieved.OfficeAssignment.Location);
    }

    [TestMethod]
    public void Course_BelongsToDepartment()
    {
        using var context = TestDbContextFactory.Create();

        var dept = new Department
        {
            Name = "Science",
            Budget = 100000,
            StartDate = new DateTime(2020, 1, 1)
        };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course
        {
            CourseID = 5000,
            Title = "Physics",
            Credits = 4,
            DepartmentID = dept.DepartmentID
        };
        context.Courses.Add(course);
        context.SaveChanges();

        var retrieved = context.Courses.Include(c => c.Department).First();
        Assert.IsNotNull(retrieved.Department);
        Assert.AreEqual("Science", retrieved.Department.Name);
    }

    [TestMethod]
    public void Notification_CanBeSavedAndRetrieved()
    {
        using var context = TestDbContextFactory.Create();

        var notification = new Notification
        {
            EntityType = "Student",
            EntityId = "1",
            Operation = "CREATE",
            Message = "Test message",
            CreatedAt = new DateTime(2023, 1, 1),
            CreatedBy = "System",
            IsRead = false
        };
        context.Notifications.Add(notification);
        context.SaveChanges();

        var retrieved = context.Notifications.First();
        Assert.AreEqual("Student", retrieved.EntityType);
        Assert.AreEqual("1", retrieved.EntityId);
        Assert.AreEqual("CREATE", retrieved.Operation);
        Assert.AreEqual("Test message", retrieved.Message);
        Assert.IsFalse(retrieved.IsRead);
    }
}

