+using ContosoUniversity.Models;
+using ContosoUniversity.Services;
+
+namespace ContosoUniversity.Tests.Services;
+
+[TestClass]
+public sealed class NotificationServiceTests
+{
+    private NotificationService _sut = null!;
+
+    [TestInitialize]
+    public void Setup()
+    {
+        _sut = new NotificationService();
+        // Drain any leftover notifications from static queue
+        while (_sut.ReceiveNotification() != null) { }
+    }
+
+    [TestCleanup]
+    public void Cleanup()
+    {
+        // Drain queue after each test
+        while (_sut.ReceiveNotification() != null) { }
+        _sut.Dispose();
+    }
+
+    [TestMethod]
+    public void SendNotification_FourParamOverload_EnqueuesNotification()
+    {
+        // Act
+        _sut.SendNotification("Student", "1", EntityOperation.CREATE);
+
+        // Assert
+        var notification = _sut.ReceiveNotification();
+        Assert.IsNotNull(notification);
+        Assert.AreEqual("Student", notification.EntityType);
+        Assert.AreEqual("1", notification.EntityId);
+        Assert.AreEqual("CREATE", notification.Operation);
+        Assert.AreEqual("System", notification.CreatedBy);
+        Assert.IsFalse(notification.IsRead);
+    }
+
+    [TestMethod]
+    public void SendNotification_FiveParamOverload_EnqueuesNotificationWithDisplayName()
+    {
+        // Act
+        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");
+
+        // Assert
+        var notification = _sut.ReceiveNotification();
+        Assert.IsNotNull(notification);
+        Assert.AreEqual("Student", notification.EntityType);
+        Assert.AreEqual("1", notification.EntityId);
+        Assert.AreEqual("CREATE", notification.Operation);
+        Assert.AreEqual("Admin", notification.CreatedBy);
+        Assert.IsTrue(notification.Message.Contains("John Doe"));
+    }
+
+    [TestMethod]
+    public void SendNotification_NullUserName_DefaultsToSystem()
+    {
+        _sut.SendNotification("Course", "101", EntityOperation.UPDATE);
+
+        var notification = _sut.ReceiveNotification();
+        Assert.IsNotNull(notification);
+        Assert.AreEqual("System", notification.CreatedBy);
+    }
+
+    [TestMethod]
+    public void ReceiveNotification_EmptyQueue_ReturnsNull()
+    {
+        var result = _sut.ReceiveNotification();
+        Assert.IsNull(result);
+    }
+
+    [TestMethod]
+    public void ReceiveNotification_PopulatedQueue_ReturnsAndRemovesNotification()
+    {
+        _sut.SendNotification("Student", "1", EntityOperation.CREATE);
+        _sut.SendNotification("Student", "2", EntityOperation.UPDATE);
+
+        var first = _sut.ReceiveNotification();
+        Assert.IsNotNull(first);
+        Assert.AreEqual("1", first.EntityId);
+
+        var second = _sut.ReceiveNotification();
+        Assert.IsNotNull(second);
+        Assert.AreEqual("2", second.EntityId);
+
+        var third = _sut.ReceiveNotification();
+        Assert.IsNull(third);
+    }
+
+    [TestMethod]
+    public void GenerateMessage_Create_ReturnsCorrectMessage()
+    {
+        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
+        var notification = _sut.ReceiveNotification();
+        Assert.AreEqual("New Student 'John Doe' has been created", notification!.Message);
+    }
+
+    [TestMethod]
+    public void GenerateMessage_Update_ReturnsCorrectMessage()
+    {
+        _sut.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE);
+        var notification = _sut.ReceiveNotification();
+        Assert.AreEqual("Course 'Chemistry' has been updated", notification!.Message);
+    }
+
+    [TestMethod]
+    public void GenerateMessage_Delete_ReturnsCorrectMessage()
+    {
+        _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);
+        var notification = _sut.ReceiveNotification();
+        Assert.AreEqual("Department 'Engineering' has been deleted", notification!.Message);
+    }
+
+    [TestMethod]
+    public void GenerateMessage_NoDisplayName_UsesIdFormat()
+    {
+        _sut.SendNotification("Student", "42", null, EntityOperation.CREATE);
+        var notification = _sut.ReceiveNotification();
+        Assert.AreEqual("New Student (ID: 42) has been created", notification!.Message);
+    }
+
+    [TestMethod]
+    public void GenerateMessage_EmptyDisplayName_UsesIdFormat()
+    {
+        _sut.SendNotification("Student", "42", "", EntityOperation.UPDATE);
+        var notification = _sut.ReceiveNotification();
+        Assert.AreEqual("Student (ID: 42) has been updated", notification!.Message);
+    }
+
+    [TestMethod]
+    public void GenerateMessage_WhitespaceDisplayName_UsesIdFormat()
+    {
+        _sut.SendNotification("Student", "42", "   ", EntityOperation.DELETE);
+        var notification = _sut.ReceiveNotification();
+        Assert.AreEqual("Student (ID: 42) has been deleted", notification!.Message);
+    }
+
+    [TestMethod]
+    public void SendNotification_QueueCapEnforcement_OldestItemsRemoved()
+    {
+        // Enqueue more than 500 items
+        for (int i = 0; i < 510; i++)
+        {
+            _sut.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
+        }
+
+        // Count remaining items
+        int count = 0;
+        while (_sut.ReceiveNotification() != null) count++;
+
+        Assert.IsTrue(count <= 500, $"Queue should be capped at 500 but had {count} items");
+    }
+
+    [TestMethod]
+    public void SendNotification_CreatedAtIsSet()
+    {
+        var before = DateTime.Now.AddSeconds(-1);
+        _sut.SendNotification("Student", "1", EntityOperation.CREATE);
+        var after = DateTime.Now.AddSeconds(1);
+
+        var notification = _sut.ReceiveNotification();
+        Assert.IsNotNull(notification);
+        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
+            $"CreatedAt {notification.CreatedAt} not in expected range [{before}, {after}]");
+    }
+
+    [TestMethod]
+    public void Dispose_DoesNotThrow()
+    {
+        var service = new NotificationService();
+        service.Dispose();
+        // No exception means success
+    }
+
+    [TestMethod]
+    public void MarkAsRead_DoesNotThrow()
+    {
+        // MarkAsRead is a no-op but should not throw
+        _sut.MarkAsRead(1);
+        _sut.MarkAsRead(999);
+    }
+}
