using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class ModelTests
{
    // === Person / FullName Tests ===

    [TestMethod]
    public void Student_FullName_ReturnsLastNameCommaFirstName()
    {
        var student = new Student { FirstMidName = "Carson", LastName = "Alexander" };

        Assert.AreEqual("Alexander, Carson", student.FullName);
    }

    [TestMethod]
    public void Instructor_FullName_ReturnsLastNameCommaFirstName()
    {
        var instructor = new Instructor { FirstMidName = "Kim", LastName = "Abercrombie" };

        Assert.AreEqual("Abercrombie, Kim", instructor.FullName);
    }

    // === ErrorViewModel Tests ===

    [TestMethod]
    public void ErrorViewModel_ShowRequestId_True_WhenRequestIdSet()
    {
        var model = new ErrorViewModel { RequestId = "abc123" };

        Assert.IsTrue(model.ShowRequestId);
    }

    [TestMethod]
    public void ErrorViewModel_ShowRequestId_False_WhenRequestIdNull()
    {
        var model = new ErrorViewModel { RequestId = null };

        Assert.IsFalse(model.ShowRequestId);
    }

    [TestMethod]
    public void ErrorViewModel_ShowRequestId_False_WhenRequestIdEmpty()
    {
        var model = new ErrorViewModel { RequestId = "" };

        Assert.IsFalse(model.ShowRequestId);
    }

    // === Student Tests ===

    [TestMethod]
    public void Student_InheritsFromPerson()
    {
        var student = new Student();

        Assert.IsInstanceOfType<Person>(student);
    }

    [TestMethod]
    public void Student_EnrollmentDate_CanBeSet()
    {
        var date = new DateTime(2023, 9, 1);
        var student = new Student { EnrollmentDate = date };

        Assert.AreEqual(date, student.EnrollmentDate);
    }

    // === Instructor Tests ===

    [TestMethod]
    public void Instructor_InheritsFromPerson()
    {
        var instructor = new Instructor();

        Assert.IsInstanceOfType<Person>(instructor);
    }

