    {
        var date = new DateTime(2000, 3, 15);
        var instructor = new Instructor { HireDate = date };

        Assert.AreEqual(date, instructor.HireDate);
    }

    // === Course Tests ===

    [TestMethod]
    public void Course_Properties_CanBeSet()
    {
        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1,
            TeachingMaterialImagePath = "/images/chem.jpg"
        };

        Assert.AreEqual(1050, course.CourseID);
        Assert.AreEqual("Chemistry", course.Title);
        Assert.AreEqual(3, course.Credits);
        Assert.AreEqual(1, course.DepartmentID);
        Assert.AreEqual("/images/chem.jpg", course.TeachingMaterialImagePath);
    }

    // === Department Tests ===

    [TestMethod]
    public void Department_Properties_CanBeSet()
    {
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000,
            StartDate = new DateTime(2020, 1, 1),
            InstructorID = 5
        };

        Assert.AreEqual(1, dept.DepartmentID);
        Assert.AreEqual("Engineering", dept.Name);
        Assert.AreEqual(350000m, dept.Budget);
        Assert.AreEqual(5, dept.InstructorID);
    }

    [TestMethod]
    public void Department_InstructorID_Nullable()
    {
        var dept = new Department { Name = "Test", InstructorID = null };

        Assert.IsNull(dept.InstructorID);
    }

    // === Enrollment Tests ===

    [TestMethod]
    public void Enrollment_Grade_Nullable()
    {
        var enrollment = new Enrollment { Grade = null };

        Assert.IsNull(enrollment.Grade);
    }

    [TestMethod]
    public void Enrollment_Grade_CanBeSet()
    {
        var enrollment = new Enrollment { Grade = Grade.A };

        Assert.AreEqual(Grade.A, enrollment.Grade);
    }

    [TestMethod]
    [DataRow(Grade.A)]
    [DataRow(Grade.B)]
    [DataRow(Grade.C)]
    [DataRow(Grade.D)]
    [DataRow(Grade.F)]
    public void Grade_AllValues_AreDefined(Grade grade)
    {
        Assert.IsTrue(Enum.IsDefined(typeof(Grade), grade));
    }

    // === EntityOperation Tests ===

    [TestMethod]
    [DataRow(EntityOperation.CREATE)]
    [DataRow(EntityOperation.UPDATE)]
    [DataRow(EntityOperation.DELETE)]
    public void EntityOperation_AllValues_AreDefined(EntityOperation operation)
    {
        Assert.IsTrue(Enum.IsDefined(typeof(EntityOperation), operation));
    }

    // === Notification Tests ===

    [TestMethod]
    public void Notification_Properties_CanBeSet()
    {
        var now = DateTime.Now;
        var notification = new Notification
        {
            Id = 1,
            EntityType = "Student",
            EntityId = "42",
            Operation = "CREATE",
            Message = "New student created",
            CreatedAt = now,
            CreatedBy = "Admin",
            IsRead = false,
            ReadAt = null
        };

        Assert.AreEqual(1, notification.Id);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("New student created", notification.Message);
        Assert.AreEqual(now, notification.CreatedAt);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
        Assert.IsNull(notification.ReadAt);
    }

    // === ViewModel Tests ===

    [TestMethod]
    public void AssignedCourseData_Properties_CanBeSet()
    {
        var data = new SchoolViewModels.AssignedCourseData
        {
            CourseID = 1050,
            Title = "Chemistry",
            Assigned = true
        };

        Assert.AreEqual(1050, data.CourseID);
        Assert.AreEqual("Chemistry", data.Title);
        Assert.IsTrue(data.Assigned);
    }

    [TestMethod]
    public void EnrollmentDateGroup_Properties_CanBeSet()
    {
        var date = new DateTime(2023, 9, 1);
        var group = new SchoolViewModels.EnrollmentDateGroup
        {
            EnrollmentDate = date,
            StudentCount = 5
        };

        Assert.AreEqual(date, group.EnrollmentDate);
        Assert.AreEqual(5, group.StudentCount);
    }

    [TestMethod]
    public void EnrollmentDateGroup_EnrollmentDate_Nullable()
    {
        var group = new SchoolViewModels.EnrollmentDateGroup { EnrollmentDate = null };

        Assert.IsNull(group.EnrollmentDate);
    }

    [TestMethod]
    public void InstructorIndexData_Properties_CanBeSet()
    {
        var data = new SchoolViewModels.InstructorIndexData
        {
            Instructors = new List<Instructor>(),
            Courses = new List<Course>(),
            Enrollments = new List<Enrollment>()
        };

        Assert.IsNotNull(data.Instructors);
        Assert.IsNotNull(data.Courses);
        Assert.IsNotNull(data.Enrollments);
    }

    // === CourseAssignment Tests ===

    [TestMethod]
    public void CourseAssignment_Properties_CanBeSet()
    {
        var ca = new CourseAssignment
        {
            InstructorID = 1,
            CourseID = 1050
        };

        Assert.AreEqual(1, ca.InstructorID);
        Assert.AreEqual(1050, ca.CourseID);
    }

    // === OfficeAssignment Tests ===

    [TestMethod]
    public void OfficeAssignment_Properties_CanBeSet()
    {
        var oa = new OfficeAssignment
        {
            InstructorID = 1,
            Location = "Room 101"
        };

        Assert.AreEqual(1, oa.InstructorID);
        Assert.AreEqual("Room 101", oa.Location);
    }
